def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' in line:
            k, v = line.split(':', 1)
            k = k.strip().lower(); v = v.strip()
            if k in ('lifetime', 'clock') and v.lstrip('-').isdigit():
                out[k] = int(v)
    return out
